#include "ir.h"
#include "pwm.h"
#include "common.h"

/** @brief  Carrier initialization of IR, The carrier of IR is generated by PWM.
 *  @param  CarrierFreq carrier frequency.
 *          This parameter value range: 30 - 60:
 *  @param  CarrierFreq carrier frequency.
 *          This parameter value range: 0 - 100:
 *  @retval None
 */
static void _IR_PwmInit (uint8_t CarrierFreq, uint8_t CarrierDuty)
{
    uint16_t period = (g_u32SystemClock/2/1000/CarrierFreq - 1) / 2;
    uint16_t duty = period  * (100-CarrierDuty) / 100;

    ENABLE_PWM;
    PWM_PWMCON_PWMMODE_SET(PWM_INDEPENDENT_MODE);
    PWM_CNTTYPE_SET(PWM_Mid_ALIGN_MODE);
    PWM0_FUNCTION_SELECTION(PWM_FUNC_PWM);
    PWM_CLKSEL_SET(PWM_CLK_PSC);
    PWM_PWMPSC01_DATA(1);
    PWM0_CNT_MODE_SET(AUTOLOAD_MODE);
    PWM_PWMP0HL_DATA((period >> 8) & 0xFF, period & 0xFF);
    PWM_PWMD0HL_DATA((duty >> 8) & 0xFF, duty & 0xFF);
    PWM_PWM0_INTTY_SET(PWM_ENDPOINT_MODE);
    ENABLE_PWM0_CNT;
    PWM_StartLoad(PWM_0);
}

/** @brief  IR initialization.
 *  @param  Init: IR initialization handle.
 *  @retval None
 */
void IR_Init (const IR_Init_t* Init)
{
    /* carrier setting */
    _IR_PwmInit(Init->CarrierFreq, Init->CarrierDuty);
    /* IR function selection : transmission */
    IR_FUNC_SEL(Init->Function);

    /* IR lcode0 signal type set. */
    IR_LCODE0_TYPE_SET(Init->Lcode0SignalType);
    /* IR lcode1 signal type set. */
    IR_LCODE1_TYPE_SET(Init->Lcode1SignalType);

    /* IR logic0 signal type set. */
    IR_LOGIC0_TYPE_SET(Init->Logic0SignalType);
    /* IR logic1 signal type set. */
    IR_LOGIC1_TYPE_SET(Init->Logic1SignalType);

    /* IR enable */
    IR_ENABLE();
}
